module top_module(
    input reset,
    input clock,
    input ee,
    input ep,
    input hold,
    output veto
    );parameter NORMAL=2'b00;
parameter HOLDING=2'b01;
parameter ONLY_EE=2'b10;

reg [1:0] unused_state;

assign veto = (unused_state == ONLY_EE) & (~ee);

always @(posedge clock)
begin
	if(reset)
	begin
		unused_state <= NORMAL;
	end else begin
		case(unused_state)
			NORMAL:  if(hold) unused_state <= HOLDING;
						else unused_state <= NORMAL;

			HOLDING: if(hold)
							if(ep) unused_state <= ONLY_EE;
							else unused_state <= HOLDING;
						else
							unused_state <= NORMAL;

			ONLY_EE: if(hold) unused_state <= ONLY_EE;
						else if (ee)
							unused_state <= NORMAL;
						else unused_state <= ONLY_EE;
		endcase
	end
end

endmodule
